// Este archivo contiene un sonido de notificación simple en base64
// Para usarlo, simplemente importa este archivo y llama a playNotificationSound()

// Sonido de notificación en formato base64 (un tono corto)
const notificationSound = 'data:audio/mp3;base64,';

// Función para reproducir el sonido de notificación
export function playNotificationSound() {
  const audio = new Audio(notificationSound);
  audio.volume = 0.5; // Volumen medio para no ser demasiado intrusivo
  audio.play().catch(error => {
    console.warn('No se pudo reproducir el sonido de notificación:', error);
  });
}